class GoogleCloudVisionClient {
  GoogleCloudVisionClient({required this.apiKey});
  final String apiKey;

  Future<Map<String, dynamic>> labelDetect(Uint8List imageBytes, {int maxResults = 10}) async {
    final url = Uri.parse('https://vision.googleapis.com/v1/images:annotate?key=$apiKey');
    final body = {
      'requests': [
        {
          'image': {'content': base64Encode(imageBytes)},
          'features': [
            {'type': 'LABEL_DETECTION', 'maxResults': maxResults}
          ],
        }
      ],
    };

    final resp = await http.post(url, headers: {'Content-Type': 'application/json'}, body: jsonEncode(body));
    if (resp.statusCode < 200 || resp.statusCode >= 300) {
      throw HttpException('Vision API error ${resp.statusCode}: ${resp.body}');
    }
    return jsonDecode(resp.body) as Map<String, dynamic>;
  }
}

class AwsS3SigV4Client {
  AwsS3SigV4Client({
    required this.accessKeyId,
    required this.secretAccessKey,
    required this.region,
  });

  final String accessKeyId;
  final String secretAccessKey;
  final String region;

  Future<http.Response> putObject({
    required String bucket,
    required String key,
    required Uint8List body,
    required String contentType,
    required DateTime now,
  }) async {
    final host = _s3Host(bucket: bucket, region: region);
    final uri = Uri.parse('https://$host/${_uriEncodePath(key)}');

    final amzDate = _amzDate(now);
    final dateStamp = _dateStamp(now);
    final payloadHash = sha256.convert(body).toString();

    final headers = <String, String>{
      'Host': host,
      'x-amz-content-sha256': payloadHash,
      'x-amz-date': amzDate,
      'Content-Type': contentType,
    };

    final signed = _signV4(
      method: 'PUT',
      uri: uri,
      region: region,
      service: 's3',
      headers: headers,
      payloadHash: payloadHash,
      now: now,
      accessKeyId: accessKeyId,
      secretAccessKey: secretAccessKey,
    );

    final allHeaders = <String, String>{...headers, 'Authorization': signed};
    return http.put(uri, headers: allHeaders, body: body);
  }
}

String _signV4({
  required String method,
  required Uri uri,
  required String region,
  required String service,
  required Map<String, String> headers,
  required String payloadHash,
  required DateTime now,
  required String accessKeyId,
  required String secretAccessKey,
}) {
  final amzDate = _amzDate(now);
  final dateStamp = _dateStamp(now);

  final canonicalUri = uri.path.isEmpty ? '/' : uri.path;
  final canonicalQueryString = _canonicalQuery(uri.queryParametersAll);

  final canonicalHeaders = _canonicalHeaders(headers);
  final signedHeaders = _signedHeaders(headers);

  final canonicalRequest = [
    method,
    canonicalUri,
    canonicalQueryString,
    canonicalHeaders,
    signedHeaders,
    payloadHash,
  ].join('\n');

  final credentialScope = '$dateStamp/$region/$service/aws4_request';
  final stringToSign = [
    'AWS4-HMAC-SHA256',
    amzDate,
    credentialScope,
    sha256.convert(utf8.encode(canonicalRequest)).toString(),
  ].join('\n');

  final signingKey = _getSignatureKey(secretAccessKey, dateStamp, region, service);
  final signature = Hmac(sha256, signingKey).convert(utf8.encode(stringToSign)).toString();

  return 'AWS4-HMAC-SHA256 Credential=$accessKeyId/$credentialScope, SignedHeaders=$signedHeaders, Signature=$signature';
}

String _canonicalHeaders(Map<String, String> headers) {
  final lower = <String, String>{};
  headers.forEach((k, v) {
    lower[k.toLowerCase().trim()] = v.trim().replaceAll(RegExp(r'\s+'), ' ');
  });
  final keys = lower.keys.toList()..sort();
  final buf = StringBuffer();
  for (final k in keys) {
    buf.write('$k:${lower[k]}\n');
  }
  return buf.toString();
}

String _signedHeaders(Map<String, String> headers) {
  final keys = headers.keys.map((e) => e.toLowerCase().trim()).toList()..sort();
  return keys.join(';');
}

String _canonicalQuery(Map<String, List<String>> q) {
  if (q.isEmpty) return '';
  final items = <String>[];
  final keys = q.keys.toList()..sort();
  for (final k in keys) {
    final vs = q[k] ?? const [];
    final sortedVs = [...vs]..sort();
    for (final v in sortedVs) {
      items.add('${_uriEncodeQuery(k)}=${_uriEncodeQuery(v)}');
    }
  }
  return items.join('&');
}

List<int> _hmacSha256(List<int> key, String data) => Hmac(sha256, key).convert(utf8.encode(data)).bytes;

List<int> _getSignatureKey(String key, String dateStamp, String regionName, String serviceName) {
  final kDate = _hmacSha256(utf8.encode('AWS4$key'), dateStamp);
  final kRegion = _hmacSha256(kDate, regionName);
  final kService = _hmacSha256(kRegion, serviceName);
  final kSigning = _hmacSha256(kService, 'aws4_request');
  return kSigning;
}

String _amzDate(DateTime t) {
  String two(int v) => v.toString().padLeft(2, '0');
  return '${t.year}${two(t.month)}${two(t.day)}T${two(t.hour)}${two(t.minute)}${two(t.second)}Z';
}

String _dateStamp(DateTime t) {
  String two(int v) => v.toString().padLeft(2, '0');
  return '${t.year}${two(t.month)}${two(t.day)}';
}

String _s3Host({required String bucket, required String region}) {
  if (region == 'us-east-1') return '$bucket.s3.amazonaws.com';
  return '$bucket.s3.$region.amazonaws.com';
}

String _s3ObjectUrl({required String bucket, required String region, required String key}) {
  final host = _s3Host(bucket: bucket, region: region);
  return 'https://$host/${_uriEncodePath(key)}';
}

String _uriEncodePath(String s) {
  return s.split('/').map((p) => Uri.encodeComponent(p)).join('/');
}

String _uriEncodeQuery(String s) => Uri.encodeQueryComponent(s);

String? _safeFileStem(String? name) {
  if (name == null || name.trim().isEmpty) return null;
  final n = name.trim();
  final dot = n.lastIndexOf('.');
  final stem = (dot > 0 ? n.substring(0, dot) : n).replaceAll(RegExp(r'[^A-Za-z0-9_\-]+'), '_');
  if (stem.isEmpty) return null;
  return stem.length > 40 ? stem.substring(0, 40) : stem;
}

String _inferExt(String contentType, {String? fallbackName}) {
  final ct = contentType.toLowerCase().trim();
  if (ct.contains('png')) return 'png';
  if (ct.contains('webp')) return 'webp';
  if (ct.contains('gif')) return 'gif';
  if (ct.contains('heic') || ct.contains('heif')) return 'heic';
  if (ct.contains('jpeg') || ct.contains('jpg')) return 'jpg';
  if (fallbackName != null) {
    final dot = fallbackName.lastIndexOf('.');
    if (dot >= 0 && dot + 1 < fallbackName.length) {
      final ext = fallbackName.substring(dot + 1).toLowerCase();
      if (ext.length <= 6) return ext;
    }
  }
  return 'jpg';
}

String _randId(int len) {
  const chars = 'abcdefghijklmnopqrstuvwxyz0123456789';
  final r = Random.secure();
  return List.generate(len, (_) => chars[r.nextInt(chars.length)]).join();
}

extension _FirstOrNull on List {
  dynamic get firstOrNull => isEmpty ? null : first;
}